const qrcode = require('qrcode-generator');
const url = 'exp://9ni2nsa-anonymous-8081.exp.direct';
const qr = qrcode(0, 'L');
qr.addData(url);
qr.make();
const n = qr.getModuleCount();
const q = 2;
let out = '';
for (let r = -q; r < n + q; r += 2) {
  let line = '';
  for (let c = -q; c < n + q; c++) {
    const top = r >= 0 && r < n && c >= 0 && c < n ? qr.isDark(r, c) : false;
    const bot = r+1 >= 0 && r+1 < n && c >= 0 && c < n ? qr.isDark(r+1, c) : false;
    line += top && bot ? '█' : top ? '▀' : bot ? '▄' : ' ';
  }
  out += line + '\n';
}
console.log(out);
console.log('modules=' + n);
"

